<template>
  <IosCard
    :title="t('tools_anti_cliche')"
    icon="fa-solid fa-broom"
    icon-color="#ff6b6b"
    :default-expanded="expanded"
    @toggle="expanded = $event"
  >
    <!-- 说明 -->
    <div class="ios-alert ios-alert-info" style="margin-bottom: 12px">
      <i class="fa-solid fa-info-circle"></i>
      <span>角色卡/世界书/开场白八股清理工具，<strong>适度清理</strong>明显八股，保持原文信息量。</span>
    </div>
    <div class="ios-alert ios-alert-warning" style="margin-bottom: 12px">
      <span>🎯 <strong>清理重点</strong>：模糊词、动物化比喻、否定句式、极端情绪、夸张修辞</span>
    </div>
    <div
      class="ios-alert"
      style="background: rgba(48, 209, 88, 0.15); color: #30d158; border: 1px solid rgba(48, 209, 88, 0.3)"
    >
      <span>✅ <strong>保持内容</strong>：核心设定、对话内容、具体动作、重要信息</span>
    </div>

    <!-- 输入区域 -->
    <div style="margin: 20px 0">
      <label class="ios-label">输入文本</label>
      <!-- 快速读取按钮 -->
      <div style="display: flex; gap: 8px; margin-bottom: 12px; flex-wrap: wrap">
        <IosButton v-for="field in charFields" :key="field.key" size="sm" @click="loadFromChar(field.key)">
          {{ field.icon }} {{ field.label }}
        </IosButton>
        <IosSelect
          v-model="selectedWorldbook"
          :options="worldbookOptions"
          placeholder="📚 从世界书读取..."
          style="min-width: 180px"
          @update:model-value="loadFromWorldbook"
        />
      </div>
      <IosTextarea
        v-model="input"
        placeholder="请输入需要清理的文本...&#10;💡 也可点击上方按钮快速读取角色卡或世界书内容"
        :rows="5"
      />
    </div>

    <!-- 清理强度 -->
    <div style="margin: 20px 0">
      <label class="ios-label">清理强度</label>
      <div style="display: flex; gap: 10px; flex-wrap: wrap">
        <label
          v-for="lvl in levels"
          :key="lvl.value"
          class="ios-level-option"
          :class="{ active: level === lvl.value }"
          :style="{ '--level-color': lvl.color }"
        >
          <input v-model="level" type="radio" :value="lvl.value" />
          <i :class="lvl.icon"></i>
          <span>{{ lvl.label }}</span>
        </label>
      </div>
      <p style="margin: 8px 0 0 0; color: rgba(235, 235, 245, 0.6); font-size: 12px">
        {{ levelDescription }}
      </p>
    </div>

    <!-- 流式开关 -->
    <div class="ios-list-item" style="border-radius: 12px; margin: 20px 0">
      <span class="ios-list-item-label">启用流式传输</span>
      <ToggleSwitch v-model="enableStreaming" />
    </div>

    <!-- 进度条 -->
    <div v-if="isProcessing && progress > 0" style="margin: 20px 0">
      <div class="ios-progress">
        <div class="ios-progress-bar" :style="{ width: progress + '%' }"></div>
      </div>
      <p style="text-align: center; margin-top: 8px; color: #0a84ff; font-size: 13px">
        清理中... {{ progress.toFixed(0) }}%
      </p>
    </div>

    <!-- 按钮 -->
    <div style="display: flex; gap: 12px; margin: 20px 0">
      <IosButton
        variant="primary"
        :disabled="isProcessing || !input.trim()"
        :loading="isProcessing"
        icon="fa-solid fa-magic"
        @click="handleProcess"
      >
        {{ isProcessing ? '处理中...' : '开始清理' }}
      </IosButton>
      <IosButton icon="fa-solid fa-trash" @click="clearForm"> 清空 </IosButton>
    </div>

    <!-- 输出区域 -->
    <div v-if="output" style="margin-top: 24px">
      <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px">
        <i class="fa-solid fa-check-circle" style="color: #30d158"></i>
        <span style="font-size: 15px; font-weight: 600; color: #fff">清理结果</span>
      </div>
      <div
        style="
          background: #1c1c1e;
          border: 1px solid rgba(84, 84, 88, 0.4);
          border-radius: 12px;
          padding: 16px;
          color: #fff;
          font-size: 14px;
          line-height: 1.7;
          white-space: pre-wrap;
          word-wrap: break-word;
          max-height: 300px;
          overflow-y: auto;
        "
      >
        {{ output }}
      </div>

      <div style="margin-top: 16px; display: flex; gap: 12px">
        <IosButton icon="fa-solid fa-copy" @click="copyResult"> 复制结果 </IosButton>
      </div>

      <!-- AI 修改功能 -->
      <div style="margin-top: 24px; padding-top: 20px; border-top: 1px solid rgba(84, 84, 88, 0.4)">
        <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px">
          <i class="fa-solid fa-wand-magic-sparkles" style="color: #ff9f0a"></i>
          <span style="font-size: 15px; font-weight: 600; color: #fff">AI 修改清理结果</span>
        </div>
        <IosTextarea
          v-model="modifyRequest"
          placeholder="描述你想要的修改，例如：把这段话改得更简洁一些..."
          :rows="3"
        />
        <div style="display: flex; gap: 12px; margin-top: 12px">
          <IosButton
            variant="primary"
            :disabled="isModifying || !modifyRequest.trim()"
            :loading="isModifying"
            icon="fa-solid fa-wand-magic-sparkles"
            style="flex: 1"
            @click="handleModify"
          >
            {{ isModifying ? '修改中...' : 'AI 修改' }}
          </IosButton>
          <IosButton :disabled="!modifyRequest.trim()" icon="fa-solid fa-eraser" @click="modifyRequest = ''">
            清空
          </IosButton>
        </div>
      </div>
    </div>
  </IosCard>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { computed, ref, watch } from 'vue';
import { useI18n } from '../../i18n';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';
import { IosButton, IosCard, IosSelect, IosTextarea, ToggleSwitch } from '../ios';

const { t } = useI18n();
const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

// Props
const props = defineProps<{
  availableWorldbooks: string[];
}>();

// Emits
const emit = defineEmits<{
  (e: 'dataChange', data: any): void;
}>();

// 状态
const expanded = ref(true);
const input = ref('');
const output = ref('');
const isProcessing = ref(false);
const isModifying = ref(false);
const progress = ref(0);
const level = ref<'light' | 'moderate' | 'deep'>('moderate');
const enableStreaming = ref(false);
const selectedWorldbook = ref('');
const modifyRequest = ref('');

// 世界书选项
const worldbookOptions = computed(() => props.availableWorldbooks.map(wb => ({ value: wb, label: wb })));

// 角色卡字段
const charFields = [
  { key: 'description', icon: '📝', label: '角色描述' },
  { key: 'personality', icon: '💭', label: '角色性格' },
  { key: 'scenario', icon: '🎬', label: '场景' },
  { key: 'mes_example', icon: '📖', label: '示例对话' },
];

// 清理强度选项
const levels = [
  { value: 'light', label: '轻度', icon: 'fa-solid fa-feather', color: '#30d158', desc: '只删除最明显的套话词汇' },
  {
    value: 'moderate',
    label: '适度',
    icon: 'fa-solid fa-balance-scale',
    color: '#0a84ff',
    desc: '删除八股词汇和文学腔',
  },
  { value: 'deep', label: '深度', icon: 'fa-solid fa-fire', color: '#ff453a', desc: '彻底清理所有八股表述' },
] as const;

const levelDescription = computed(() => levels.find(l => l.value === level.value)?.desc || '');

// 监听数据变化
watch(
  [input, output, level, enableStreaming, modifyRequest],
  () => {
    emit('dataChange', {
      input: input.value,
      output: output.value,
      level: level.value,
      enableStreaming: enableStreaming.value,
      modifyRequest: modifyRequest.value,
    });
  },
  { deep: true },
);

// 从角色卡读取
const loadFromChar = (field: string) => {
  try {
    const tav = (window as any).TavernHelper;
    if (tav?.getCharData) {
      const char = tav.getCharData('current');
      if (char) {
        const fieldMap: Record<string, string> = {
          description: char.description || char.data?.description || '',
          personality: char.personality || char.data?.personality || '',
          scenario: char.scenario || char.data?.scenario || '',
          mes_example: char.mes_example || char.data?.mes_example || '',
        };
        const content = fieldMap[field] || '';
        if (content) {
          input.value = content;
          window.toastr.success(`已读取角色卡 ${field}`);
        } else {
          window.toastr.warning(`角色卡 ${field} 为空`);
        }
        return;
      }
    }
    window.toastr.warning('请先选择一个角色');
  } catch (e) {
    console.error('读取角色卡失败:', e);
    window.toastr.error('读取失败');
  }
};

// 从世界书读取
const loadFromWorldbook = async () => {
  if (!selectedWorldbook.value) return;

  try {
    const tav = (window as any).TavernHelper;
    if (tav?.getWorldbook) {
      const entries = await tav.getWorldbook(selectedWorldbook.value);
      if (entries?.length) {
        const allContent = entries
          .filter((e: any) => e.content)
          .map((e: any) => `【${e.name || e.comment || '条目'}】\n${e.content}`)
          .join('\n\n');

        if (allContent) {
          input.value = allContent;
          window.toastr.success(`已读取 ${entries.length} 个条目`);
        }
      }
    }
  } catch (e) {
    console.error('读取世界书失败:', e);
    window.toastr.error('读取失败');
  }
  selectedWorldbook.value = '';
};

// 获取 Prompt
const getPrompt = (lvl: string): string => {
  const baseRules = `# 常见八股清单
**模糊词**：一丝、一抹、似乎、仿佛、不知为何
**强调词**：极其、无比、竟然、居然
**眼神描写**："眼里闪过xxx"、"嘴角上扬"
**动物比喻**："像小兽"、"像猫咪"`;

  if (lvl === 'light') {
    return `你是文本编辑助手，进行轻度八股清理。
# 轻度清理原则
- 只删除最明显的套话
- 保留大部分文学表达
- 信息量100%保持
${baseRules}
直接输出清理后的文本，不要任何解释。`;
  }

  if (lvl === 'deep') {
    return `你是文本编辑助手，进行深度八股清理。
# 深度清理原则
- 彻底清理所有八股
- 转为简洁人话
- 保持核心信息
${baseRules}
直接输出清理后的文本，不要任何解释。`;
  }

  return `你是专业的文本编辑助手，专注于清理角色卡/世界书中的AI文学腔和八股表述。
# 第一原则：信息量守恒
${baseRules}
# 必须保留
1. 所有""内的台词
2. 核心设定
直接输出清理后的文本，不要任何解释。`;
};

// 处理清理
const handleProcess = async () => {
  if (!input.value.trim()) {
    window.toastr.warning('请输入需要清理的文本');
    return;
  }

  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('AI正在清理...');

    const messages = [
      { role: 'system', content: getPrompt(level.value) },
      { role: 'user', content: input.value },
    ];

    const result = await callAIWithTavernSupport(messages, settings.value, {
      onProgress: (p: number) => (progress.value = p),
    });

    output.value = result;
    window.toastr.success('文本清理完成！');
  } catch (error) {
    console.error('反八股清理失败:', error);
    window.toastr.error(translateError(error, '文本清理'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

// 复制结果
const copyResult = () => {
  if (!output.value) {
    window.toastr.warning('没有可复制的内容');
    return;
  }
  copyToClipboard(output.value, '清理结果已复制到剪贴板');
};

// AI 修改
const handleModify = async () => {
  if (!modifyRequest.value.trim() || !output.value) return;

  try {
    isModifying.value = true;
    window.toastr.info('AI正在修改...');

    const messages = [
      {
        role: 'system',
        content: '你是一个文本编辑助手。根据用户的修改需求，对提供的文本进行修改。直接输出修改后的结果。',
      },
      {
        role: 'user',
        content: `当前文本：\n${output.value}\n\n修改需求：${modifyRequest.value}`,
      },
    ];

    const result = await callAIWithTavernSupport(messages, settings.value, {
      onProgress: (p: number) => (progress.value = p),
    });

    output.value = result;
    window.toastr.success('修改完成！');
  } catch (error) {
    console.error('反八股修改失败:', error);
    window.toastr.error(translateError(error, '修改'));
  } finally {
    isModifying.value = false;
    progress.value = 0;
  }
};

// 清空表单
const clearForm = () => {
  input.value = '';
  output.value = '';
  modifyRequest.value = '';
};

// 暴露方法供父组件调用
defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      input.value = data.input || '';
      output.value = data.output || '';
      level.value = data.level || 'moderate';
      enableStreaming.value = data.enableStreaming || false;
      modifyRequest.value = data.modifyRequest || '';
    }
  },
});
</script>

